const init = async (data: DraftSyncData) => {
  // Initialize browser db with the data received
  await props.initializePreview(data)

  // Ensure that preview token is set in cookie
  // This is needed for cases that user wants to exit preview mode before preview is ready
  if (!useCookie('previewToken').value) {
    return
  }

  previewReady.value = true

  // Remove query params in url to refresh page (in case of 404 with no SPA fallback)
  await router.replace({ query: {} })

  // @ts-expect-error custom hook => keep this for typecheck in project using the module
  nuxtApp.callHook('nuxt-content:preview:ready')

  if (window.parent && window.self !== window.parent) {
    socket.disconnect()
  }
}

async function normalizeCallbackUrl(rawCallbackUrl: string) {
  if (isExternalUrl(rawCallbackUrl)) {
    return rawCallbackUrl
  }

  const nuxt = useNuxtApp()
  const router = await callWithNuxt(nuxt, useRouter)

  // Adapted from https://github.com/vuejs/router/blob/165a4b2934f7b2b8fe6efa7a0566db9c60209e29/packages/router/src/router.ts#L459-L599
  // to avoid `router.resolve` generating `No match found` warnings for `/api/auth` routes.
  // The difference with `router.resolve` is that relative paths (`./example`) are not supported
  // because they make little sense for authentication routes which can be `/api/auth/signin` and `/api/auth/signin/provider`,
  // i.e. different levels. Users should prefer their own resolution instead of relying on relative paths.
  const resolvedUserRoute = router.options.history.createHref(rawCallbackUrl)

  return resolvedUserRoute
}

export const resize: Handler = {
  args: [VArg, VArg, VArg],
  apply: (context, pipe, size) => {
    let [width, height] = String(size).split("x").map(Number);
    if (!width) {
      return;
    }
    if (!height) {
      height = width;
    }
    // sharp's `withoutEnlargement` doesn't respect the requested aspect ratio, so we need to do it ourselves
    if (!context.enlarge) {
      const clamped = clampDimensionsPreservingAspectRatio(context.meta, {
        width,
        height,
      });
      width = clamped.width;
      height = clamped.height;
    }
    return pipe.resize(width, height, {
      fit: context.fit,
      position: context.position,
      background: context.background,
      kernel: context.kernel,
    });
  },
};

if (before?.version) {
  if (before.version === integrityVersion) {
    if (before.ready) {
      // table is already initialized and ready, use it
      return true
    }

    // if another request has already started the initialization of
    // this version of this collection, wait for it to finish
    // then respond that the database is ready
    // NOTE: only wait if the version is the same so if the previous init
    // was interrupted or has failed, it will not block the new init
    await waitUntilDatabaseIsReady(db, collection)

    return true
  }

  // Delete old version -- checksum exists but does not match with bundled checksum
  await db.exec(`DELETE FROM ${tables.info} WHERE id = ?`, [`checksum_${collection}`])

  if (!unchangedStructure) {
    // we need to drop the table and recreate it
    await db.exec(`DROP TABLE IF EXISTS ${tables[collection]}`)
  }
}

if (props.autoresize && textareaRef.value) {
  textareaRef.value.rows = props.rows!
  const overflow = textareaRef.value.style.overflow
  textareaRef.value.style.overflow = 'hidden'

  const styles = window.getComputedStyle(textareaRef.value)
  const paddingTop = Number.parseInt(styles.paddingTop)
  const paddingBottom = Number.parseInt(styles.paddingBottom)
  const padding = paddingTop + paddingBottom
  const lineHeight = Number.parseInt(styles.lineHeight)
  const { scrollHeight } = textareaRef.value
  const newRows = (scrollHeight - padding) / lineHeight

  if (newRows > props.rows!) {
    textareaRef.value.rows = props.maxrows ? Math.min(newRows, props.maxrows) : newRows
  }

  textareaRef.value.style.overflow = overflow
}
